// ══ FIRESTORE ══
async function loadData(uid){
  try{const s=await db.collection('users').doc(uid).collection('data').doc('main').get();return s.exists?s.data():null;}
  catch(e){console.error(e);return null;}
}
async function saveDataFS(uid,d){
  try{
    // Write full data to subcollection
    await db.collection('users').doc(uid).collection('data').doc('main').set(d);
    // Also update parent /users/{uid} doc so admin listing works
    await db.collection('users').doc(uid).set({
      email: d.settings?.email||'',
      displayName: d.settings?.displayName||'',
      lastSaved: d.lastSaved||null,
      lastUpdated: d.lastUpdated||{}
    },{merge:true});
  }
  catch(e){console.error(e);}
}

// ══ AUTH STATE ══
auth.onAuthStateChanged(async user=>{
  if(user){
    CU=user.uid;
    // Ensure parent /users/{uid} doc exists for admin listing
    db.collection('users').doc(CU).set({email:user.email||'',firstSeen:user.metadata.creationTime||null},{merge:true}).catch(()=>{});
    const loaded=await loadData(CU);
    D=loaded||defData();
    if(!D.snapshots)D.snapshots=[];
    if(!D.portfolio)D.portfolio=defData().portfolio;
    if(!D.portfolios){
      // Migrate from old single portfolio to multi-portfolio
      const existingItems=D.portfolio&&D.portfolio.length&&D.portfolio.some(p=>p.name||p.value)
        ? D.portfolio
        : [{name:'',category:'מניות חו"ל',value:'',targetPct:''}];
      D.portfolios=[{id:1,brokerName:'',items:existingItems}];
    }
    // Ensure all portfolio items are preserved
    // Ensure all NW rows have currency field
    ['assets','investments','savings','debts'].forEach(sec=>{
      (D.nwData[sec].rows||[]).forEach(row=>{if(!row.currency)row.currency='ILS';});
    });
    D.portfolios.forEach(port=>{
      if(!port.items||!port.items.length)port.items=[{name:'',category:'מניות חו"ל',value:'',targetPct:''}];
    });
    // migrate pension tracks
    (D.pension||[]).forEach(p=>{if(!p.tracks)p.tracks=[{name:'',pct:''}];if(p.fees&&!p.feesDeposit){p.feesDeposit=p.fees;delete p.fees;}});
    // sanitize NW periods - clear NaN values from bad date parsing
    D.nwPeriods=(D.nwPeriods||[]).map(p=>{
      if(!p||p.includes('NaN')||p.trim()==='')return '';
      return p;
    });
    // pad to 6
    if(!D.nwPeriodsCount)D.nwPeriodsCount=Math.max(6,D.nwPeriods.length);
    while(D.nwPeriods.length<D.nwPeriodsCount)D.nwPeriods.push('');
    // migrate nwData
    ['assets','investments','savings','debts'].forEach(sec=>{
      if(D.nwData[sec]&&!D.nwData[sec].rows){
        D.nwData[sec]={rows:Object.entries(D.nwData[sec]).map(([name,vals])=>({name,vals:Array.isArray(vals)?vals:nw6()}))};
      }
      if(!D.nwData[sec])D.nwData[sec]={rows:[]};
      // Pad vals arrays — fixes "incomplete number" when rows were created with fewer periods
      (D.nwData[sec].rows||[]).forEach(row=>{
        while(row.vals.length<D.nwPeriodsCount)row.vals.push('');
      });
    });
    document.getElementById('init-loader').style.display='none';
    injectLogos();
    document.getElementById('auth').style.display='none';
    document.getElementById('app').style.display='flex';
    document.getElementById('uname').textContent=user.displayName||user.email;
    // Show admin nav only for admin email
    document.getElementById('admin-nav-btn').style.display=user.email===ADMIN_EMAIL?'':'none';
    if(!D.settings)D.settings={displayName:'',email:user.email||'',age:'',notifyEmail:user.email||'',gender:'male'};
    if(!D.settings.gender)D.settings.gender='male'; // migrate existing users
    if(!D.lastUpdated)D.lastUpdated={goals:null,pension:null,nw:null};
    renderAll();
    goTo('dash',document.querySelector('.nbtn'));
    // Prompt for name on first login if not set
    if(!D.settings.displayName){
      setTimeout(()=>{
        document.getElementById('welcome-modal').style.display='flex';
        document.getElementById('welcome-name-input').focus();
      },400);
    } else if(!localStorage.getItem('tour_done_'+CU)){
      setTimeout(()=>startTour(),900);
    }
  }else{
    CU=null;D={};
    document.getElementById('init-loader').style.display='none';
    document.getElementById('app').style.display='none';
    document.getElementById('auth').style.display='flex';
    injectLogos();
  }
});

async function saveWelcomeName(){
  const name=document.getElementById('welcome-name-input').value.trim();
  const emailRaw=(document.getElementById('welcome-email-input')?.value||'').trim().replace(/[​-‏‪-‮⁦-⁩﻿]/g,'').toLowerCase();
  const errEl=document.getElementById('welcome-err');
  const showErr=msg=>{if(errEl){errEl.textContent=msg;errEl.style.display='block';}};
  if(!name){document.getElementById('welcome-name-input').style.borderColor='var(--red)';showErr('נא להכניס שם');return;}
  if(!emailRaw||!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(emailRaw)){
    const eEl=document.getElementById('welcome-email-input');
    if(eEl)eEl.style.borderColor='var(--red)';
    showErr('נא להכניס כתובת מייל תקינה');return;
  }
  D.settings.displayName=name;
  D.settings.email=emailRaw;
  document.getElementById('uname').textContent=name;
  document.getElementById('welcome-modal').style.display='none';
  await auth.currentUser?.updateProfile({displayName:name});
  await saveDataFS(CU,D);
  markDirty();
  localStorage.setItem('onboarding_gender_'+CU,'1');
  goTo('settings',document.getElementById('nav-settings'));
}

// ══ AUTH ACTIONS ══
function aTab(t){
  document.getElementById('tl').classList.toggle('on',t==='l');
  document.getElementById('tr').classList.toggle('on',t==='r');
  document.getElementById('lf').style.display=t==='l'?'block':'none';
  document.getElementById('rf').style.display=t==='r'?'block':'none';
  document.getElementById('aerr').style.display='none';
}
function showErr(m){
  const e=document.getElementById('aerr');
  // Reset teal styling that doForgotPassword may have applied
  e.style.background='';e.style.borderColor='';e.style.color='';
  e.textContent=m;e.style.display='block';
}
async function doLogin(){
  const e=v('lu'),p=v('lp');
  if(!e||!p)return showErr('נא למלא את כל השדות');
  const btn=document.querySelector('#lf .btnmain');
  if(btn){btn.disabled=true;btn.textContent='מתחבר...';}
  try{await auth.signInWithEmailAndPassword(e,p);}
  catch(err){showErr(fbErr(err.code)||'שגיאת התחברות — בדוק אימייל וסיסמה');}
  finally{if(btn){btn.disabled=false;btn.textContent='כניסה →';}}
}
async function doReg(){
  const name=v('rn'),e=v('ru'),p=v('rp');
  if(!name||!e||!p)return showErr('נא למלא את כל השדות');
  if(p.length<6)return showErr('סיסמה חייבת להיות לפחות 6 תווים');
  try{
    const cred=await auth.createUserWithEmailAndPassword(e,p);
    await cred.user.updateProfile({displayName:name});
    await saveDataFS(cred.user.uid,defData());
  }catch(err){showErr(fbErr(err.code));}
}
async function doLogout(){await auth.signOut();}
async function doForgotPassword(){
  const email=document.getElementById('lu').value.trim();
  if(!email){
    showErr('הכנס את האימייל שלך קודם, ואז לחץ "שכחתי סיסמה"');
    return;
  }
  try{
    // continueUrl redirects user back to the app after completing reset on Firebase's page
    await auth.sendPasswordResetEmail(email,{url:'https://tomcoani.github.io/financial-tracker/',handleCodeInApp:false});
    document.getElementById('aerr').style.background='rgba(66,235,214,.1)';
    document.getElementById('aerr').style.borderColor='rgba(66,235,214,.3)';
    document.getElementById('aerr').style.color='var(--teal)';
    showErr('✓ מייל איפוס נשלח ל-'+email+'. בדוק את תיבת הדואר — כולל תיקיית ספאם!');
  }catch(e){
    showErr(fbErr(e.code)||'שגיאה בשליחת מייל איפוס');
  }
}
function fbErr(c){
  const m={'auth/user-not-found':'משתמש לא קיים','auth/wrong-password':'סיסמה שגויה',
    'auth/email-already-in-use':'אימייל זה כבר קיים','auth/invalid-email':'אימייל לא תקין',
    'auth/invalid-credential':'אימייל או סיסמה שגויים','auth/too-many-requests':'יותר מדי ניסיונות'};
  return m[c]||'שגיאה: '+c;
}

// ══ DIRTY / SAVE ══
function markDirty(){
  dirty=true;
  document.getElementById('save-bar').style.display='flex';
  document.getElementById('save-status').textContent='';
  // auto-save after 10 seconds of inactivity
  clearTimeout(autoSaveTimer);
  autoSaveTimer=setTimeout(()=>manualSave(),10000);
}
async function manualSave(){
  if(!CU||!dirty)return;
  collectAll();
  D.lastSaved = new Date().toISOString();
  await saveDataFS(CU,D);
  dirty=false;
  document.getElementById('save-bar').style.display='none';
  updateLastUpdatedBars();
  showToast('נשמר בענן ☁️');
}
function collectAll(){
  D.monthly=document.getElementById('monthly').value;
  D.penNotes=document.getElementById('pen-notes').value;
  D.gnotes=document.getElementById('gnotes').value;
  const cfZeroEl=document.getElementById('cf-zero');
  if(cfZeroEl){
    const raw=(cfZeroEl.dataset.numRaw||cfZeroEl.value).replace(/,/g,'');
    if(raw)D.cfZero=raw;
  }
  const cfCreditEl=document.getElementById('cf-credit');
  if(cfCreditEl){
    const raw=(cfCreditEl.dataset.numRaw||cfCreditEl.value).replace(/,/g,'');
    D.cfCredit=raw||'';
  }
}

// ══ NAV ══
let _lastTab='';
function goTo(id,btn){
  document.querySelectorAll('.panel').forEach(p=>p.classList.remove('on'));
  document.querySelectorAll('.nbtn').forEach(b=>b.classList.remove('on'));
  document.getElementById('p-'+id).classList.add('on');
  btn.classList.add('on');
  _lastTab=id;
  syncMobileNav(id);
  if(id==='dash')renderDash();
  if(id==='history')renderHistory();
  if(id==='portfolio'){renderPortfolio();renderPortfolioCharts();}
  if(id==='nw'){syncNWFromPension();renderNW();}
  if(id==='settings')renderSettings();
  if(id==='admin')renderAdmin();
}

// ══ RENDER ALL ══
function renderAll(){
  document.getElementById('monthly').value=D.monthly||'';
  document.getElementById('pen-notes').value=D.penNotes||'';
  document.getElementById('gnotes').value=D.gnotes||'';
  const cfZeroEl=document.getElementById('cf-zero');
  if(cfZeroEl){
    const n=D.cfZero?parseFloat(String(D.cfZero).replace(/,/g,'')):0;
    if(n){cfZeroEl.value=n;cfZeroEl.dataset.numRaw=String(n);}
    else{cfZeroEl.value='';delete cfZeroEl.dataset.numRaw;}
  }
  const cfCurEl=document.getElementById('cf-currency');
  if(cfCurEl&&D.cfCurrency)cfCurEl.value=D.cfCurrency;
  const cfCreditEl=document.getElementById('cf-credit');
  if(cfCreditEl){
    const n=D.cfCredit?parseFloat(String(D.cfCredit).replace(/,/g,'')):0;
    if(n){cfCreditEl.value=n;cfCreditEl.dataset.numRaw=String(n);}
    else{cfCreditEl.value='';delete cfCreditEl.dataset.numRaw;}
  }
  const cfBalEl=document.getElementById('cf-balance');
  if(cfBalEl){cfBalEl.value='';delete cfBalEl.dataset.numRaw;}
  const cfExpEl=document.getElementById('cf-expenses');
  if(cfExpEl)cfExpEl.value='';
  renderCfFixed();
  // Only render what's immediately needed
  renderSettings();
  renderDash();
  updateLastUpdatedBars();
  // Defer heavy renders to next tick
  setTimeout(()=>{
    migrateGoalLocs();
    renderGoals();
    renderLocs();
    renderLocsAutoSummary();
  },50);
  setTimeout(()=>{
    renderPension();
    renderNW();
    renderPortfolio();
    attachAllNumFormats();
  },100);
}
